function() {
  var eventName = {{Event}};
  var className = {{Click Classes}};  
  // 检查是否是弹窗可见性事件且目标元素是弹窗
  var condition = eventName === 'gtm.elementVisibility' && className === 'ant-modal-content';
  if (condition) {
    // 确保 dataLayer 至少有 2 个事件
    if (window.dataLayer.length < 2) {
      return '';
    }

    // 获取前一个事件
    var prevEventIndex = window.dataLayer.length - 2;
    var prevEvent = window.dataLayer[prevEventIndex];

    // 检查前一个事件是否是点击事件
    if (prevEvent.event !== 'gtm.click') {
      return '';
    }

    // 返回点击的按钮文本
    return prevEvent['gtm.element'] ? prevEvent['gtm.element'].innerText : '';
  }

  return '';
}

