function() {
    var ele = {{cjs-click_ele_closest}};
    var res = [];

    var spans = ele.querySelectorAll(':scope > span') || [];

    for (var i = 0; i < spans.length; i++) {
        var span = spans[i];

        if (span.textContent && span.textContent.trim()) {
            res.push(span.textContent);
        }
    }

    return res.join(' ');
}

