function(){
  // 点击弹窗内容区
  if({{Event}} === 'gtm.click' && {{Click Element}}.closest('.ant-modal-content')) {
    return window.localStorage.getItem('spm_d')
  }
  var btnText = {{cjs-open_modal_btn_text}};
  var modalTitle = {{cjs-modal_title}};
  var btnTextStr = btnText ? 'btn_' + btnText : ''
  var modalTitleStr = modalTitle ? 'modal_title=' + modalTitle : ''
  if(!btnTextStr && !modalTitleStr) {
    return '';
  }
  var tempStr = btnTextStr ? btnTextStr + '&' + modalTitleStr : modalTitleStr;
  if(!tempStr) {
    return '';
  }
  var resStr = 'd' + {{const-spm_split_flag}} + tempStr + '_' + {{Random Number}};
  window.localStorage.setItem('spm_d', resStr)
  return resStr
}

